int n, m, k;
vector<pair<int,int>> sol;

bool valido(int c, int fila, int col) {
    for (int i = 0; i < c; i++) {
        if (sol[i].first == fila || sol[i].second == col)
            return false;
    }
    return true;
}

void bt(int c) {
    if (c == k) {
        // registrar solución
        return;
    }
    for (int f = 0; f < n; f++) {
        for (int cc = 0; cc < m; cc++) {
            if (/* celda válida */) {
                sol[c] = {f, cc};
                bt(c + 1);
                // backtrack automático al reasignar
            }
        }
    }
}

solucion_codigo:
int n, m, k;
vector<pair<int,int>> sol;
vector<vector<pair<int,int>>> soluciones;

bool valido(int c, int fila, int col) {
    for (int i = 0; i < c; i++) {
        if (sol[i].first == fila || sol[i].second == col)
            return false;
    }
    return true;
}

void bt(int c) {
    if (c == k) {
        soluciones.push_back(sol);
        return;
    }
    for (int f = 0; f < n; f++) {
        for (int cc = 0; cc < m; cc++) {
            if (valido(c, f, cc)) {
                sol[c] = {f, cc};
                bt(c + 1);
            }
        }
    }
}

int main() {
    sol.resize(k);
    bt(0);
}
